// // This comment suggests that the circuit inverts the input signal on each clock edge, but in reality, it toggles the output between 0 and 1.
module top_module (
	input clk,
	input rst_n,
	output reg q);always @(posedge clk or negedge rst_n)
	if (!rst_n)
		q <= 0;
	else
		q <= ~q;

endmodule
